package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  private static class JsonObjectSubclass extends JsonObject {
    @Override
    public JsonElement deepCopy() {
      return new JsonObjectSubclass();
    }
  }

  private static class JsonElementSubclass extends JsonElement {
    @Override
    public JsonElement deepCopy() {
      return this;
    }
  }

  @Test
  void isJsonObject_shouldReturnTrue_whenInstanceIsJsonObject() {
    JsonElement element = new JsonObjectSubclass();
    assertTrue(element.isJsonObject());
  }

  @Test
  void isJsonObject_shouldReturnFalse_whenInstanceIsNotJsonObject() {
    JsonElement element = new JsonElementSubclass();
    assertFalse(element.isJsonObject());
  }
}
